import{_ as a,o as t,c as r,a2 as o}from"./chunks/framework.ChXBHUFc.js";const m=JSON.parse('{"title":"IMU streaming","description":"","frontmatter":{},"headers":[],"relativePath":"guide/imu-streaming.md","filePath":"guide/imu-streaming.md","lastUpdated":1782681346000}'),s={name:"guide/imu-streaming.md"};function i(n,e,d,c,l,h){return t(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="imu-streaming" tabindex="-1">IMU streaming <a class="header-anchor" href="#imu-streaming" aria-label="Permalink to &quot;IMU streaming&quot;">​</a></h1><p>The Triki streams raw accelerometer + gyroscope over BLE once you send a multi-byte start command on RX. <strong>Verified live here.</strong></p><h2 id="start-the-stream" tabindex="-1">Start the stream <a class="header-anchor" href="#start-the-stream" aria-label="Permalink to &quot;Start the stream&quot;">​</a></h2><p>Write to RX <code>…0002</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>20 10 00 D0 07 68 00 03</span></span></code></pre></div><p>(<code>68 00</code> = 104 → ~104 Hz sample rate.)</p><h2 id="stream-format" tabindex="-1">Stream format <a class="header-anchor" href="#stream-format" aria-label="Permalink to &quot;Stream format&quot;">​</a></h2><p>The device then pushes 14-byte frames on TX <code>…0003</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>offset  0    2     4     6      8      10     12</span></span>
<span class="line"><span>        22 00 gyroX gyroY gyroZ accelX accelY accelZ</span></span>
<span class="line"><span>header ─┘     └──────────────── 6 × int16 LE ──────┘</span></span></code></pre></div><p>Bytes 0–1 are the <code>22 00</code> header; the six axes follow as signed int16, little-endian at offsets 2 / 4 / 6 (gyro) and 8 / 10 / 12 (accel). Scales:</p><ul><li><strong>gyro / 14.286</strong> → deg/s — LSM6DSL ±2000 dps (70 mdps/LSB). The older <code>131.0</code> was an MPU-6050 ±250 dps value carried over from notes; it under-rotated ~9×.</li><li><strong>accel / 2048.0</strong> → g — LSM6DSL ±16 g (flat token reads +2048 = 1 g).</li></ul><p>Frames arrive in bursts at ~104 Hz (the default; the rate is selectable — see <a href="./ble-protocol#sample-rate-odr">Sample rate</a>).</p><h3 id="startup-behaviour" tabindex="-1">Startup behaviour <a class="header-anchor" href="#startup-behaviour" aria-label="Permalink to &quot;Startup behaviour&quot;">​</a></h3><ul><li>The <strong>first ~20 frames after start are noise</strong> — discard them before trusting the data (to be verified).</li><li>For a clean gravity/zero baseline, let the token sit <strong>flat and still</strong> for a moment before sending the start command.</li><li>There is no stop opcode: the stream ends when you disconnect.</li></ul><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h2><p>Under shaking, gyro swings ±10000+, and the accel axis aligned with gravity reads ≈ +2048 (= 1 g) — decode confirmed at ~104 Hz. Reader: <code>tools/ble_imu_stream.py</code> (see <a href="./tooling">Tooling</a>).</p><p>This is sufficient to use the token as a <strong>motion controller</strong> — recover orientation via 6-axis gyro + accel fusion. The <a href="./library"><code>triki-controller</code></a> package ships two interchangeable filters: <strong>Madgwick</strong> (one gain, <code>beta</code>) and <strong>VQF</strong> (accel low-pass time constant <code>tauAcc</code>; ported from <a href="https://github.com/dlaidig/vqf" target="_blank" rel="noreferrer">VQF</a> by Daniel Laidig, MIT). Both produce the same right-handed <code>[w, x, y, z]</code> frame and, being magnetometer-free, drift in yaw — re-zero heading as needed.</p><blockquote><p>Note: the single-byte opcodes (<code>0x05</code> / <code>0x07</code> / <code>0x09</code> / …) are a separate diagnostic/management interface — raw IMU is NOT there; it only comes from the start-stream command above.</p></blockquote>`,18)])])}const g=a(s,[["render",i]]);export{m as __pageData,g as default};
